import com.blue.util.JacksonUtils;
import org.apache.http.HttpHost;
import org.apache.http.auth.AuthScope;
import org.apache.http.auth.UsernamePasswordCredentials;
import org.apache.http.impl.client.BasicCredentialsProvider;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchRequestBuilder;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.transport.TransportClient;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.transport.InetSocketTransportAddress;
import org.elasticsearch.common.unit.TimeValue;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.plugins.Plugin;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.transport.client.PreBuiltTransportClient;

import javax.net.ssl.SSLContext;
import java.io.IOException;
import java.net.InetAddress;
import java.net.UnknownHostException;
import java.security.NoSuchAlgorithmException;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class ElasticsearchService {

    private static final int SIZE = 100;

    public List<Message> getLatestMessages(String host, int port, String scheme, String username, String password) throws IOException {
        RestHighLevelClient restHighLevelClient = new RestHighLevelClient(RestClient.builder(new HttpHost(host, port, scheme))
                .setHttpClientConfigCallback(httpAsyncClientBuilder -> {
                    httpAsyncClientBuilder.disableAuthCaching();
                    if (username != null && password != null) {
                        return httpAsyncClientBuilder.setDefaultCredentialsProvider(() -> {
                            return new BasicCredentialsProvider().setCredentials(AuthScope.ANY,
                                    new UsernamePasswordCredentials(username, password));
                        });
                    } else {
                        return httpAsyncClientBuilder;
                    }
                }));

        SearchRequest searchRequest = new SearchRequest("_all");
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        searchSourceBuilder.query(QueryBuilders.matchAllQuery());
        searchSourceBuilder.size(SIZE);
        searchSourceBuilder.sort("timestamp");
        searchRequest.source(searchSourceBuilder);

        SearchResponse searchResponse = restHighLevelClient.search(searchRequest, RequestOptions.DEFAULT);
        SearchHit[] hits = searchResponse.getHits().getHits();

        List<Message> messages = new ArrayList<>();
        Arrays.stream(hits).forEach(hit -> {
            Message message = JacksonUtils.fromJsonString(hit.getSourceAsString(), Message.class);
            messages.add(message);
        });

        return messages;
    }

    public List<Message> getLatestMessages(String host, int port, String username, String password) throws UnknownHostException, NoSuchAlgorithmException {
        Settings settings = Settings.builder()
                .put("client.transport.sniff", true)
                .put("cluster.name", "your_cluster_name")
                .put("xpack.security.user", username + ":" + password)
                .put("request.headers.X-Found-Cluster", "your_cluster_id")
                .put("ssl.keystore.path", "path_to_your_keystore_file")
                .put("ssl.truststore.path", "path_to_your_truststore_file")
                .put("ssl.keystore.password", "your_keystore_password")
                .put("ssl.truststore.password", "your_truststore_password")
                .put("ssl.verify_hostname", false)
                .build();

        SSLContext sslContext = SSLContext.getDefault();
        TransportClient transportClient = new PreBuiltTransportClient(settings, (Class<? extends Plugin>[]) null)
                .addTransportAddress(new InetSocketTransportAddress(InetAddress.getByName(host), port))
                .setHttpClientConfigCallback(httpClientBuilder -> {
                    if (username != null && password != null) {
                        BasicCredentialsProvider credentialsProvider = new BasicCredentialsProvider();
                        credentialsProvider.setCredentials(AuthScope.ANY,
                                new UsernamePasswordCredentials(username, password));
                        httpClientBuilder.setDefaultCredentialsProvider(credentialsProvider);
                    }
                    return httpClientBuilder.setSSLContext(sslContext);
                });

        SearchRequestBuilder searchRequestBuilder = transportClient.prepareSearch("_all");
        searchRequestBuilder.setQuery(QueryBuilders.matchAllQuery());
        searchRequestBuilder.setSize(SIZE);
        searchRequestBuilder.addSort("timestamp", SortOrder.DESC);
        searchRequestBuilder.setTimeout(TimeValue.timeValueSeconds(10));

        SearchResponse searchResponse = searchRequestBuilder.execute().actionGet();
        SearchHit[] hits = searchResponse.getHits().getHits();

        List<Message> messages = new ArrayList<>();
        for (SearchHit hit : hits) {
            Message message = JacksonUtils.fromJsonString(hit.getSourceAsString(), Message.class);
            messages.add(message);
        }

        return messages;
    }

}
